#include <stdio.h>

typedef enum { IDLE, RUNNING, STOPPED } State;

int main(void) {
    int raw;
    if (scanf("%d", &raw) != 1) return 1;
    if (raw < IDLE || raw > STOPPED) { puts("invalid"); return 0; }
    State state = (State)raw;
    switch (state) {
        case IDLE: puts("idle"); break;
        case RUNNING: puts("running"); break;
        case STOPPED: puts("stopped"); break;
    }
    return 0;
}
